    function showToast(msg, isError) {
        var t = document.getElementById("req-toast");
        if (!t) return;
        t.textContent = msg;
        t.style.display = "block";
        t.style.borderColor = isError ? "var(--red)" : "var(--accent)";
        t.style.color = isError ? "var(--red)" : "var(--text)";
        clearTimeout(t._timer);
        t._timer = setTimeout(function () { t.style.display = "none"; }, 2000);
        setTimeout(function () {
            document.addEventListener("click", function _dismiss() {
                t.style.display = "none";
                clearTimeout(t._timer);
                document.removeEventListener("click", _dismiss);
            }, { once: true });
        }, 100);
    }

    function renderRequestsModal(requests) {
        var list = document.getElementById("requests-modal-list");
        if (!list) return;
        if (!requests.length) {
            list.innerHTML = '<div style="color:var(--text-muted);text-align:center;padding:1.5rem;font-family:var(--font-pixel);font-size:0.8rem;">No pending requests found.</div>';
            return;
        }
        list.innerHTML = "";
        requests.forEach(function (r) {
            var row = makeReqRow(r);
            list.appendChild(row);
        });
    }

    function updateRequestsBadge(count) {
        var dot = document.getElementById("requests-badge-dot");
        if (!dot) return;
        if (count > 0) {
            dot.style.display = "block";
            dot.textContent = count > 9 ? "9+" : count;
        } else {
            dot.style.display = "none";
            dot.textContent = "";
        }
        var oldBtn = document.getElementById("requests-badge-btn");
        if (oldBtn) oldBtn.style.display = "none"; // legacy cleanup
    }

    function renderSidebarRequests(requests) {
        var area = document.getElementById("sidebar-requests-area");
        var list = document.getElementById("sidebar-requests-list");
        if (!area || !list) return;

        if (!requests || requests.length === 0) {
            area.style.display = "none";
            return;
        }

        area.style.display = "block";
        list.innerHTML = "";
        requests.forEach(function (r) {
            var item = document.createElement("div");
            item.className = "request-item-sidebar";
            item.innerHTML = `
                <span class="name" title="${r.from_id}">${r.from_id}</span>
                <div class="actions">
                    <button class="btn-sidebar-req accept" style="background:var(--green); color:var(--bg);">✔</button>
                    <button class="btn-sidebar-req reject" style="background:var(--red); color:var(--bg);">✖</button>
                    <button class="btn-sidebar-req block" style="background:#555; color:var(--text); font-size:0.6rem;">BLK</button>
                </div>
            `;

            item.querySelector(".accept").onclick = function () {
                item.style.opacity = "0.5";
                getJson(API + "/contacts/respond", {
                    method: "POST",
                    body: JSON.stringify({ from_id: r.from_id, action: "accept" })
                }).then(function () {
                    item.remove();
                    showToast(r.from_id + " added!", false);
                    refreshOnlineUsers();
                    checkIncomingRequests();
                });
            };

            item.querySelector(".reject").onclick = function () {
                item.style.opacity = "0.5";
                getJson(API + "/contacts/respond", {
                    method: "POST",
                    body: JSON.stringify({ from_id: r.from_id, action: "reject" })
                }).then(function () {
                    item.remove();
                    showToast("Request from " + r.from_id + " rejected.", false);
                    checkIncomingRequests();
                });
            };

            item.querySelector(".block").onclick = function () {
                item.style.opacity = "0.5";
                getJson(API + "/contacts/respond", {
                    method: "POST",
                    body: JSON.stringify({ from_id: r.from_id, action: "block" })
                }).then(function () {
                    item.remove();
                    showToast(r.from_id + " blocked.", true);
                    checkIncomingRequests();
                });
            };

            list.appendChild(item);
        });
    }

    var _lastRequestFromIds = [];

    function checkIncomingRequests() {
        if (!currentClientId) return;
        getJson(API + "/contacts/requests/incoming")
            .then(function (data) {
                var reqs = data.requests || [];
                updateRequestsBadge(reqs.length);

                var now = new Date();
                var newReqs = [];
                var oldReqs = [];

                reqs.forEach(function (r) {
                    var created = r.created_at ? new Date(r.created_at) : now;
                    var ageMins = (now - created) / (1000 * 60);
                    if (ageMins < 10) {
                        newReqs.push(r);
                    } else {
                        oldReqs.push(r);
                    }
                });

                // Update the pending invitations button with aged-out count
                if (viewPendingBtn) {
                    if (oldReqs.length > 0) {
                        viewPendingBtn.textContent = "View Pending Invitations (" + oldReqs.length + ")";
                        viewPendingBtn.style.color = "var(--accent)";
                        viewPendingBtn.style.borderColor = "var(--accent)";
                    } else {
                        viewPendingBtn.textContent = "View Pending Invitations";
                        viewPendingBtn.style.color = "rgba(255,255,255,0.7)";
                        viewPendingBtn.style.borderColor = "rgba(255,255,255,0.2)";
                    }
                }

                // Show/hide inline requests area based on NEW requests
                if (newReqs.length > 0) {
                    if (inlineRequestsArea) inlineRequestsArea.style.display = "block";
                    openFriendRequestsModal(newReqs);
                } else {
                    if (inlineRequestsArea) inlineRequestsArea.style.display = "none";
                }

                // Update the aged-out modal list if it exists
                if (oldReqs.length > 0) {
                    renderRequestsModal(oldReqs);
                } else {
                    var modalList = document.getElementById("requests-modal-list");
                    if (modalList) {
                        modalList.innerHTML = '<div style="color:var(--accent);text-align:center;padding:2.5rem;font-family:var(--font-pixel);text-shadow:0 0 5px rgba(var(--accent-rgb),0.3);">No aged-out invitations.</div>';
                        modalList.style.background = "#0b0e14";
                    }
                }

                // Notify only for newly arrived requests
                reqs.forEach(function (r) {
                    if (_lastRequestFromIds.indexOf(r.from_id) === -1) {
                        // Play a soft ping
                        try {
                            var ctx = new (window.AudioContext || window.webkitAudioContext)();
                            var osc = ctx.createOscillator();
                            var gain = ctx.createGain();
                            osc.connect(gain);
                            gain.connect(ctx.destination);
                            osc.frequency.value = 880;
                            osc.type = "sine";
                            gain.gain.setValueAtTime(0.3, ctx.currentTime);
                            gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.4);
                            osc.start(ctx.currentTime);
                            osc.stop(ctx.currentTime + 0.4);
                        } catch (e) { }
                        // Browser notification
                        if (window.Notification && Notification.permission === "granted") {
                            new Notification("New friend request", { body: r.from_id + " wants to add you.", icon: "" });
                        } else if (window.Notification && Notification.permission !== "denied") {
                            Notification.requestPermission();
                        }
                    }
                });
                _lastRequestFromIds = reqs.map(function (r) { return r.from_id; });
            })
            .catch(function () { });
    }
    window.checkIncomingRequests = checkIncomingRequests;

    var _shownOutgoing = {};
    function checkOutgoingRequests() {
        if (!currentClientId) return;
        getJson(API + "/contacts/requests/outgoing")
            .then(function (data) {
                var reqs = data.requests || [];
                reqs.forEach(function (r) {
                    var key = r.to_id + ":" + r.status;
                    if (_shownOutgoing[key]) return;
                    _shownOutgoing[key] = true;
                    var msg = "";
                    if (r.status === "accepted") {
                        msg = r.to_id + " accepted your request!";
                        refreshOnlineUsers();
                    } else if (r.status === "rejected") {
                        msg = r.to_id + " rejected your request.";
                    } else if (r.status === "blocked") {
                        msg = "User not found.";
                    }
                    if (msg && addFriendModalStatus) {
                        addFriendModalStatus.textContent = msg;
                        addFriendModalStatus.style.color = r.status === "accepted" ? "var(--green)" : "var(--red)";
                        if (addContactModal && addContactModal.style.display !== "flex") {
                            addContactModal.style.display = "flex";
                        }
                        setTimeout(function () {
                            if (addFriendModalStatus) addFriendModalStatus.textContent = "";
                        }, 4000);
                    }
                });
            })
            .catch(function () { });
    }

