    function handleAttachmentSelection(intent, type) {
        chatAttachmentIntent = intent;
        if (chatAttachMenu) chatAttachMenu.classList.remove("is-visible");

        var input;
        if (type === "image") input = chatCustomImageInput;
        else if (type === "audio") input = chatAudioInput;
        else if (type === "video") input = chatVideoInput;
        else if (type === "docs") input = chatDocsInput;

        if (input) {
            // If the user selects a non-image file and is in stego mode, switch to AES and warn them
            var mode = currentMode();
            if (type !== "image" && (mode === "stego" || mode === "both")) {
                var aesRadio = document.querySelector('input[name="chat-mode"][value="aes"]');
                if (aesRadio) {
                    aesRadio.checked = true;
                    // Trigger the visibility update if any
                    aesRadio.dispatchEvent(new Event('change'));
                }
                showOutput(document.getElementById("chat-status"), "Non-image attachments only support AES. Switched to AES mode.", true);
            }
            input.click();
        }
    }

    function setupFileInput(input, labelText) {
        if (!input) return;
        input.addEventListener("change", function (e) {
            var file = e.target.files && e.target.files[0];
            if (!file) return;
            var reader = new FileReader();
            reader.onload = function (evt) {
                chatAttachmentB64 = evt.target.result;
                chatAttachmentFilename = file.name;
                if (chatImagePreview && chatImagePreviewImg && chatImagePreviewLabel) {
                    // For non-images, we still want a preview icon or similar if possible.
                    // For now, we'll just show the label and hide the img or use a placeholder.
                    if (file.type.startsWith("image/")) {
                        chatImagePreviewImg.src = chatAttachmentB64;
                        chatImagePreviewImg.style.display = "block";
                    } else {
                        chatImagePreviewImg.style.display = "none";
                    }
                    chatImagePreviewLabel.textContent = labelText + ": " + file.name;
                    chatImagePreview.classList.add("is-visible");
                }
            };
            reader.readAsDataURL(file);
        });
    }

