    // VIEW PENDING INVITATIONS — renders inline inside the Add Contact modal
    function makeReqRow(r) {
        var row = document.createElement("div");
        row.className = "request-row";
        row.setAttribute("data-req-row", r.from_id);

        var dateStr = r.created_at ? new Date(r.created_at).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : "";

        row.innerHTML = `
            <div class="request-info">
                <span class="request-name">${r.from_id}</span>
                <span class="request-meta">Wants to add you &bull; ${dateStr}</span>
            </div>
            <div class="request-actions">
                <button class="req-accept req-btn" style="background:var(--green);color:var(--bg);" title="Accept">✔</button>
                <button class="req-reject req-btn" style="background:var(--red);color:var(--bg);" title="Reject">✖</button>
                <button class="req-block req-btn" style="background:#555;color:var(--text);font-size:0.6rem;" title="Block">BLK</button>
            </div>
        `;

        function respond(action) {
            getJson(API + "/contacts/respond", {
                method: "POST",
                body: JSON.stringify({ from_id: r.from_id, action: action })
            }).then(function () {
                row.remove();
                if (action === "accept") {
                    if (addFriendModalStatus) { addFriendModalStatus.textContent = r.from_id + " added!"; addFriendModalStatus.style.color = "var(--green)"; }
                    refreshOnlineUsers();
                } else if (action === "reject") {
                    if (addFriendModalStatus) { addFriendModalStatus.textContent = "Request rejected."; addFriendModalStatus.style.color = "var(--text-muted)"; }
                } else {
                    if (addFriendModalStatus) { addFriendModalStatus.textContent = r.from_id + " blocked."; addFriendModalStatus.style.color = "var(--red)"; }
                }
                setTimeout(function () { if (addFriendModalStatus) addFriendModalStatus.textContent = ""; }, 2000);

                // Update badges correctly
                var totalRemaining = document.querySelectorAll("[data-req-row]").length;
                updateRequestsBadge(totalRemaining);

                // Check current container
                var container = row.parentElement;
                if (container && !container.querySelector("[data-req-row]")) {
                    var isInline = (container.id === "inline-requests-list");
                    container.innerHTML = `<div data-placeholder="1" style="color:var(--text-muted);text-align:center;padding:1.5rem;font-family:var(--font-pixel);">${isInline ? "No latest requests." : "No aged-out invitations."}</div>`;
                }
            }).catch(function (err) {
                if (addFriendModalStatus) { addFriendModalStatus.textContent = err.message || "Error"; addFriendModalStatus.style.color = "var(--red)"; }
            });
        }
        row.querySelector(".req-accept").onclick = function (e) { e.stopPropagation(); respond("accept"); };
        row.querySelector(".req-reject").onclick = function (e) { e.stopPropagation(); respond("reject"); };
        row.querySelector(".req-block").onclick = function (e) { e.stopPropagation(); respond("block"); };
        return row;
    }

    openFriendRequestsModal = function (reqs) {
        if (!inlineRequestsArea || !inlineRequestsList) return;
        inlineRequestsArea.style.display = "block";

        // If reqs passed in directly (from poll), use them — otherwise fetch
        function renderReqs(reqs) {
            // Filter to ensure only new ones are in this inline list
            var now = new Date();
            var filtered = reqs.filter(function (r) {
                var created = r.created_at ? new Date(r.created_at) : now;
                return ((now - created) / (1000 * 60)) < 10;
            });

            _lastRequestFromIds = filtered.map(function (r) { return r.from_id; });

            // Diff: remove rows no longer in list
            var existing = inlineRequestsList.querySelectorAll("[data-req-row]");
            var newIds = filtered.map(function (r) { return r.from_id; });
            existing.forEach(function (el) {
                if (newIds.indexOf(el.getAttribute("data-req-row")) === -1) el.remove();
            });

            // Add rows that are new
            var existingIds = Array.from(inlineRequestsList.querySelectorAll("[data-req-row]")).map(function (el) { return el.getAttribute("data-req-row"); });
            filtered.forEach(function (r) {
                if (existingIds.indexOf(r.from_id) === -1) {
                    // Remove "no pending" placeholder if present
                    var placeholder = inlineRequestsList.querySelector("[data-placeholder]");
                    if (placeholder) placeholder.remove();
                    inlineRequestsList.appendChild(makeReqRow(r));
                }
            });

            // Show placeholder if empty
            if (!inlineRequestsList.querySelector("[data-req-row]")) {
                inlineRequestsList.innerHTML = '<div data-placeholder="1" style="color:var(--accent);text-align:center;padding:1.5rem;font-family:var(--font-pixel);opacity:0.6;">No latest requests.</div>';
            }
        }

        if (reqs) {
            renderReqs(reqs);
        } else {
            getJson(API + "/contacts/requests/incoming")
                .then(function (data) { renderReqs(data.requests || []); })
                .catch(function (err) {
                    inlineRequestsList.innerHTML = '<div style="color:var(--red);text-align:center;padding:1rem;">Error: ' + (err.message || "") + '</div>';
                });
        }
    };

