            // Render current avatar in modal
            var avatarDisplay = document.getElementById("profile-avatar-display");
            if (avatarDisplay) {
                renderAvatarToElement(avatarDisplay, currentAvatar, currentAvatarData);
            }

            // Sync the avatar picker selection to the current avatar
            var avatarPicker = document.getElementById("profile-avatar-picker");
            if (avatarPicker) {
                avatarPicker.querySelectorAll(".avatar-option").forEach(function (o) {
                    o.classList.toggle("is-selected", o.getAttribute("data-avatar") === currentAvatar);
                });
            }

            profileModal.style.display = "flex";
